configuration.jsScript:
// raw_severity_code comes from the edge device (pre-fog, unconfirmed)
var sc = msg.raw_severity_code !== undefined ? Number(msg.raw_severity_code) : 0;
msg.raw_severity_code = sc;

// Human-readable label derived from edge model output only
msg.hypoxia_level = sc === 2 ? 'SEVERE' : sc === 1 ? 'MILD_UNCONFIRMED' : 'NORMAL';
msg.edge_processed_ts = new Date().toISOString();

// Feature attribution annotation (Novel Addition 3 — edge layer)
msg.alert_reason = (msg.top_trigger_feature && msg.top_trigger_feature !== 'n/a')
    ? msg.top_trigger_feature + ' (z=' + msg.trigger_feature_zscore + ')'
    : 'n/a';

return {msg: msg, metadata: metadata, msgType: msgType};

// Route on raw_severity_code from the edge model.
// Note: mild alerts are UNCONFIRMED at this stage — fog confirmation
// is handled in the Fog Intelligence Chain via fog_confirmed_severity.
var sc = Number(msg.raw_severity_code);
if (sc === 2) return ['severe'];
if (sc === 1) return ['mild'];
return ['normal'];

configuration.alarmDetailsBuildJs:
// Only edge fields — fog confirmation fields (fog_tier, adaptive_threshold)
// are on FogGateway_01, not on this edge device
var d = {};
d.spo2 = msg.spo2;
d.p_severe = msg.p_severe;
d.edge_confidence = msg.edge_confidence;
d.alert_reason = msg.alert_reason;
d.device_id = msg.device_id;
return d;

// Advisory alarm from raw edge output — fog layer will confirm/suppress.
// The fog_confirmed_severity field on FogGateway_01 is the authoritative decision.
var d = {};
d.spo2 = msg.spo2;
d.p_abnormal = msg.p_abnormal;
d.edge_confidence = msg.edge_confidence;
d.alert_reason = msg.alert_reason;
d.device_id = msg.device_id;
d.note = 'Unconfirmed at edge — check FogGateway_01 fog_confirmed_severity';
return d;

